/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {

    // Helper to convert [x, y, z] array to a unique string key
    const pointToKey = (p) => p.join(',');

    // Helper to convert key string back to [x, y, z] array
    const keyToPoint = (key) => key.split(',').map(Number);

    const targetKey = pointToKey(target);

    // Set of all unique points discovered so far. Stored as string keys.
    let availablePointsKeys = new Set();

    // --- Step 0: Check Initial Generation (k=0) ---
    for (const p of points) {
        const key = pointToKey(p);
        if (key === targetKey) {
            return 0;
        }
        availablePointsKeys.add(key);
    }

    // If there are 0 or 1 points, no new generation is possible.
    if (availablePointsKeys.size < 2) {
        return -1;
    }

    let k = 0;
    let hasNewPoints = true;

    while (hasNewPoints) {
        k++;
        const previousPointsKeys = Array.from(availablePointsKeys);
        const newPointsKeys = new Set();

        // Iterate over all unique pairs of distinct points available so far
        for (let i = 0; i < previousPointsKeys.length; i++) {
            for (let j = i + 1; j < previousPointsKeys.length; j++) {

                const keyA = previousPointsKeys[i];
                const keyB = previousPointsKeys[j];

                const pointA = keyToPoint(keyA);
                const pointB = keyToPoint(keyB);

                // Calculate the new point c = [floor((x1+x2)/2), ...]
                const cx = Math.floor((pointA[0] + pointB[0]) / 2);
                const cy = Math.floor((pointA[1] + pointB[1]) / 2);
                const cz = Math.floor((pointA[2] + pointB[2]) / 2);

                const newPoint = [cx, cy, cz];
                const newPointKey = pointToKey(newPoint);

                // Add to new points set, regardless of whether it's already known, 
                // as we need to check for target existence in this generation.
                newPointsKeys.add(newPointKey);
            }
        }

        // Check if the target was generated in this step (k)
        if (newPointsKeys.has(targetKey)) {
            return k;
        }

        // Determine genuinely new points to add to the master set
        let newlyAddedCount = 0;
        for (const key of newPointsKeys) {
            if (!availablePointsKeys.has(key)) {
                availablePointsKeys.add(key);
                newlyAddedCount++;
            }
        }

        // If no genuinely new points were added, the process terminates.
        if (newlyAddedCount === 0) {
            return -1;
        }
    }

    // Should be unreachable if the logic is correct, but as a fallback
    return -1;
}

