import scala.collection.mutable

// Define a case class for coordinates to ensure proper hashing and equality in Scala Sets
case class Point(x: Long, y: Long, z: Long)

def points(pointsInput: Array[Array[Long]], targetInput: Array[Long]): Long = {

    // Convert input arrays to Point objects
    val initialPoints = pointsInput.map(arr => Point(arr(0), arr(1), arr(2))).toSet
    val targetPoint = Point(targetInput(0), targetInput(1), targetInput(2))

    // Step 0: Check Initial Generation (k=0)
    if (initialPoints.contains(targetPoint)) {
        return 0L
    }

    // S_0: Set of all unique points found so far.
    var availablePoints: Set[Point] = initialPoints.toSet

    // k tracks the generation number, starting from 0 (already checked)
    var k: Long = 0L

    // Loop for k = 1, 2, 3, ...
    while (true) {
        k += 1

        // Get the sequence of points available at the start of this generation (S_{k-1})
        // We must use a sequence/list derived from the set to iterate over pairs efficiently.
        val sPreviousSeq = availablePoints.toSeq

        // Calculate N_k: New points generated in this step.
        val newPointsGenerated = mutable.Set[Point]()

        // Iterate over all unique pairs (a, b) from sPreviousSeq
        // Since sPreviousSeq contains unique points (by coordinate), this satisfies the distinct point requirement.
        for (i <- 0 until sPreviousSeq.length) {
            for (j <- i + 1 until sPreviousSeq.length) {

                val pA = sPreviousSeq(i)
                val pB = sPreviousSeq(j)

                // Calculate c = [floor((x1+x2)/2), ...]
                // Since all coordinates are non-negative, integer division (Long / 2L) performs floor.
                val cx = (pA.x + pB.x) / 2L
                val cy = (pA.y + pB.y) / 2L
                val cz = (pA.z + pB.z) / 2L

                val newPoint = Point(cx, cy, cz)

                // Check if target is generated in this step (N_k)
                if (newPoint == targetPoint) {
                    return k
                }

                // Collect all generated points
                newPointsGenerated.add(newPoint)
            }
        }

        // Determine genuinely new points to add to the master set
        val newlyAdded = newPointsGenerated.filterNot(availablePoints.contains)

        if (newlyAdded.isEmpty) {
            // No new unique points were added in this generation, process terminates.
            return -1L
        }

        // Add all newly discovered points to the master set S_k = S_{k-1} U N_k
        newlyAdded.foreach(availablePoints.add)
    }
}

